"use client";

import { useState } from "react";
import type { LevelOption, SortConfig, StatView } from "@/types/filters";
import { TRADITIONAL_SORT_OPTIONS, KANEXT_SORT_OPTIONS } from "./filter-drawer";

interface Props {
  levelKey: string | null;
  teamIds: string[];
  positions: string[];
  archetypes: string[];
  sort: SortConfig;
  statView: StatView;
  levels: LevelOption[];
  onNavigate: (screen: "level" | "teams" | "position" | "archetype" | "updates") => void;
  onSwitchView: (view: StatView) => void;
  onSelectSort: (sort: SortConfig) => void;
  onReset: () => void;
  onApply: () => void;
  onClose: () => void;
}

export default function DrawerMain({
  levelKey,
  teamIds,
  positions,
  archetypes,
  sort,
  statView,
  levels,
  onNavigate,
  onSwitchView,
  onSelectSort,
  onReset,
  onApply,
  onClose,
}: Props) {
  const [sortOpen, setSortOpen] = useState(false);

  const levelLabel = levelKey
    ? levels.find((l) => l.levelKey === levelKey)?.displayName ?? levelKey
    : "All";
  const teamLabel = teamIds.length === 0 ? "All" : `${teamIds.length} selected`;
  const posLabel = positions.length === 0 ? "All" : `${positions.length} selected`;
  const archLabel = archetypes.length === 0 ? "All" : `${archetypes.length} selected`;

  type Screen = "level" | "teams" | "position" | "archetype" | "updates";
  const rows: { label: string; value: string; screen: Screen }[] = [
    { label: "Level", value: levelLabel, screen: "level" },
    { label: "Teams", value: teamLabel, screen: "teams" },
    { label: "Position", value: posLabel, screen: "position" },
    { label: "Archetype", value: archLabel, screen: "archetype" },
    { label: "Updates", value: "\u2014", screen: "updates" },
  ];

  const sortOptions = statView === "traditional" ? TRADITIONAL_SORT_OPTIONS : KANEXT_SORT_OPTIONS;

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <div className="flex items-center justify-between px-5 py-4 border-b border-slate-200">
        <h2 className="text-base font-bold text-slate-900">Filter &amp; Sort</h2>
        <button onClick={onClose} className="p-1 hover:bg-slate-100 rounded transition-colors">
          <svg className="w-5 h-5 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      {/* Scrollable content */}
      <div className="flex-1 overflow-y-auto">
        {/* Filter rows */}
        {rows.map((row) => (
          <button
            key={row.screen}
            onClick={() => onNavigate(row.screen)}
            className="w-full flex items-center justify-between px-5 py-4 border-b border-slate-100 hover:bg-slate-50 transition-colors text-left"
          >
            <span className="text-sm font-semibold text-slate-900">{row.label}</span>
            <span className="flex items-center gap-2">
              <span className="text-sm text-slate-500">{row.value}</span>
              <svg className="w-4 h-4 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
              </svg>
            </span>
          </button>
        ))}

        {/* Sort By — collapsible */}
        <button
          onClick={() => setSortOpen((prev) => !prev)}
          className="w-full flex items-center justify-between px-5 py-4 border-b border-slate-100 hover:bg-slate-50 transition-colors text-left"
        >
          <span className="text-sm font-semibold text-slate-900">Sort By</span>
          <svg
            className={`w-4 h-4 text-slate-400 transition-transform ${sortOpen ? "rotate-180" : ""}`}
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        </button>

        {sortOpen && (
          <>
            {/* Traditional / KaNeXT toggle */}
            <div className="px-5 py-3 border-b border-slate-100">
              <div className="flex rounded overflow-hidden border border-slate-300">
                <button
                  onClick={() => onSwitchView("traditional")}
                  className={`flex-1 px-3 py-1.5 text-xs font-bold uppercase tracking-wide transition-colors ${
                    statView === "traditional"
                      ? "bg-slate-900 text-white"
                      : "bg-white text-slate-600 hover:bg-slate-50"
                  }`}
                >
                  Traditional
                </button>
                <button
                  onClick={() => onSwitchView("kanext")}
                  className={`flex-1 px-3 py-1.5 text-xs font-bold uppercase tracking-wide transition-colors ${
                    statView === "kanext"
                      ? "bg-slate-900 text-white"
                      : "bg-white text-slate-600 hover:bg-slate-50"
                  }`}
                >
                  KaNeXT
                </button>
              </div>
            </div>

            {/* Sort options grid */}
            <div className="grid grid-cols-2">
              {sortOptions.map((opt) => {
                const active = sort.key === opt.key;
                return (
                  <button
                    key={opt.key}
                    onClick={() => {
                      if (active) {
                        onSelectSort({ key: opt.key, direction: sort.direction === "desc" ? "asc" : "desc" });
                      } else {
                        onSelectSort({ key: opt.key, direction: opt.defaultDirection });
                      }
                    }}
                    className="flex items-start gap-3 px-5 py-3 border-b border-slate-100 hover:bg-slate-50 transition-colors text-left [&:nth-child(odd)]:border-r"
                  >
                    <span
                      className={`w-5 h-5 rounded-full border-2 flex items-center justify-center shrink-0 mt-0.5 ${
                        active ? "border-slate-900" : "border-slate-300"
                      }`}
                    >
                      {active && <span className="w-2.5 h-2.5 rounded-full bg-slate-900" />}
                    </span>
                    <span className="flex-1 min-w-0">
                      <span className={`text-sm block ${active ? "font-bold text-slate-900" : "text-slate-700"}`}>
                        {opt.label}
                        {active && (
                          <span className="ml-1 text-slate-400">
                            {sort.direction === "desc" ? "\u2193" : "\u2191"}
                          </span>
                        )}
                      </span>
                      {opt.traits && (
                        <span className="text-[11px] text-slate-400 block mt-0.5 leading-tight">
                          {opt.traits}
                        </span>
                      )}
                    </span>
                  </button>
                );
              })}
            </div>
          </>
        )}
      </div>

      {/* Footer */}
      <div className="flex items-center justify-between px-5 py-4 border-t border-slate-200 bg-white">
        <button
          onClick={onReset}
          className="text-sm font-bold uppercase tracking-wider text-slate-500 hover:text-slate-900 transition-colors"
        >
          Reset Filters
        </button>
        <button
          onClick={onApply}
          className="px-5 py-2.5 bg-slate-900 text-white text-sm font-bold uppercase tracking-wider rounded hover:bg-slate-800 transition-colors"
        >
          Apply Filters
        </button>
      </div>
    </div>
  );
}
